+    // ── postorder_next additional tests ───────────────────────
+
+    #[test]
+    fn postorder_next_on_single_leaf_fails() {
+        let c = Tree::<i32>::Leaf(1).cursor();
+        assert!(c.postorder_next().is_err());
+    }
