+    #[test]
+    fn build_ten_leaf_tree_verify_values() {
+        let mut t = Tree::<i32, ()>::new()
+            .cursor()
+            .assign_top(0)
+            .unwrap()
+            .tree();
+        for i in 1..10 {
+            t = t
+                .cursor()
+                .go_to_nth_leaf(i - 1)
+                .unwrap()
+                .split_leaf_and_insert_right(i as i32)
+                .unwrap()
+                .tree();
+        }
+        // Verify each leaf value
+        for i in 0..10 {
+            let mut c = t.cursor().go_to_nth_leaf(i).unwrap();
