+    #[test]
+    fn go_left_then_go_right_sibling_via_up() {
+        let t = Tree::<i32, i32>::new()
+            .cursor()
+            .assign_top(1)
+            .unwrap()
+            .split_leaf_and_insert_right(2)
+            .unwrap()
+            .tree();
+
+        // Navigate: root → left → up → right
+        let mut c = t
+            .cursor()
+            .go_left()
+            .unwrap()
+            .go_up()
+            .unwrap()
+            .go_right()
+            .unwrap();
+        assert!(c.is_right());
+        assert_eq!(*c.leaf_mut().unwrap(), 2);
+    }
